        self._plugins.pop(name)
        return r[bool].ok(True)

    def _convert_to_query_result(
        self,
        sql: str,
        data: Sequence[t.Dict],
    ) -> m.DbOracle.QueryResult:
        """Convert raw query data to QueryResult model."""
        if not data:
            return m.DbOracle.QueryResult(
                query=sql,
                columns=[],
                rows=[],
                row_count=0,
                unique_id="",
                created_at=datetime.now(UTC),
                domain_events=[],
                result_data=[],
                query_hash="",
                explain_plan="",
            )
        first_row = data[0].root
        columns = list(first_row.keys())
        rows = [
            m.DbOracle.RowData(
                values=[str(value) for value in row.root.values()],
            )
            for row in data
        ]
        return m.DbOracle.QueryResult(
            query=sql,
            columns=columns,
            rows=rows,
            row_count=len(data),
            unique_id="",
            created_at=datetime.now(UTC),
            domain_events=[],
            result_data=[],
            query_hash="",
            explain_plan="",
        )

