        default_factory=lambda: t.ConfigMap(
            root={
                "default_output_format": "table",
                "show_execution_time": "True",
                "auto_confirm_operations": "False",
                "connection_timeout": 30,
                "query_limit": 1000,
            },
        ),
        description="User preference settings for CLI output",
    )

