            def __contains__(self, key: str) -> bool:
                """Check if key is in table metadata."""
                return key in self.model_dump()

        class TypeMapping(FlextModels.Entity):
            """Singer-to-Oracle type mapping."""

            mapping: t.StrMapping = Field(
